// Content expansion helpers
function sec(paras,links) {
  let idx=0;const r=[]
  for(const p of paras){
    const n=3+Math.abs(crypto.createHash("md5").update(p).digest().readUInt32BE(0))%4
    let t=p
    for(let i=0;i<n&&idx<links.length;i++){
      const pos=40+Math.abs(crypto.createHash("md5").update(t+idx).digest().readUInt32BE(0))%Math.min(120,Math.max(20,t.length-60))
      t=t.slice(0,pos)+" "+links[idx]+". "+t.slice(pos);idx++
    }r.push(t)
  }
  return r.join(" ")
}
const N=`
Fundamentally, Essential, Critically, Strategically, Importantly, Notably, Specifically, Consequently, Typically, Ultimately,
Broadly, In practice, From our analysis, Based on our evaluation, Across deployments, In our testing,
For most organizations, From an operational standpoint, Looking at the data, When properly configured, After thorough assessment
`.split(",").map(s=>s.trim()).filter(Boolean)
function exp(seeds,links,extra){
  const h=crypto.createHash("md5").update(seeds.join("")).digest().readUInt32BE(0)
  const r=[]
  for(let i=0;i<seeds.length;i++){
    let p=seeds[i]
    if(extra){
      const ei=Math.abs(h*(i+1))%extra.length
      p+=" "+extra[ei]+" "+(i%2===0?"This approach enables organizations to maximize their investment in enterprise software solutions while minimizing operational overhead and ensuring compliance with industry standards and regulatory frameworks.":"Organizations implementing these solutions typically see measurable improvements across key performance indicators including efficiency, accuracy, and user satisfaction within the first quarter of adoption.")
    }
    const n=3+Math.abs(h*(i+7))%4;let t=p
    let idx=Math.abs(h*(i+3))%Math.max(1,links.length-5)
    for(let j=0;j<n&&idx<links.length;j++){
      const pos=50+Math.abs(h*(idx+1))%Math.min(100,Math.max(20,t.length-80))
      t=t.slice(0,pos)+" "+links[idx]+". "+t.slice(pos);idx=(idx+3)%links.length
    }r.push(t)
  }
  return r.join(" ")
}
function blinks(cat,slug,n,seed) {
  const l=[], u=new Set()
  const cr=CAT.R.filter(r=>r.cat===cat&&r.slug!==slug)
  for(const r of pickN(cr,Math.ceil(n*0.22),seed+"-r")){if(u.size>=n)break;u.add(r.slug);l.push('<a href="/reviews/'+r.slug+'">'+r.name+'</a>')}
  for(const r of pickN(CAT.R.filter(r=>r.cat!==cat&&r.slug!==slug),Math.ceil(n*0.12),seed+"-or")){if(u.size>=n)break;u.add(r.slug);l.push('<a href="/reviews/'+r.slug+'">'+r.name+'</a>')}
  const tc=CAT.C.filter(c=>c.slug.includes(slug)||c.slug.includes(slug.replace(/-/g,"")))
  for(const c of pickN(tc,Math.ceil(n*0.1),seed+"-c")){if(u.size>=n)break;u.add(c.slug);l.push('<a href="/comparisons/'+c.slug+'">comparison</a>')}
  for(const b of pickN(CAT.B.filter(b=>b.cat===cat),Math.ceil(n*0.08),seed+"-b")){if(u.size>=n)break;u.add(b.slug);l.push('<a href="/best/'+b.slug+'">best '+cat.toLowerCase()+'</a>')}
  for(const b of pickN(CAT.B.filter(b=>b.cat!==cat),Math.ceil(n*0.05),seed+"-ob")){if(u.size>=n)break;u.add(b.slug);l.push('<a href="/best/'+b.slug+'">guide</a>')}
  for(const i of pickN(CAT.I,Math.ceil(n*0.08),seed+"-i")){if(u.size>=n)break;u.add(i.slug);l.push('<a href="/industries/'+i.slug+'">'+i.name+' software</a>')}
  const cu=CAT.U.filter(u=>u.cat===cat)
  for(const uu of pickN(cu,Math.ceil(n*0.05),seed+"-u")){if(u.size>=n)break;u.add(uu.slug);l.push('<a href="/use-cases/'+uu.slug+'">use case</a>')}
  for(const g of pickN(CAT.G,Math.ceil(n*0.05),seed+"-g")){if(u.size>=n)break;u.add(g.slug);l.push('<a href="/guides/'+g.slug+'">guide</a>')}
  const cs=CAT.S.filter(s=>cat.includes(s.cat)||s.cat.includes(cat))
  for(const s of pickN(cs,Math.ceil(n*0.05),seed+"-s")){if(u.size>=n)break;u.add(s.slug);l.push('<a href="/statistics/'+s.slug+'">statistics</a>')}
  for(const g of pickN(CAT.GL,Math.ceil(n*0.03),seed+"-gl")){if(u.size>=n)break;u.add(g.slug);l.push('<a href="/glossary/'+g.slug+'">glossary</a>')}
  return l
}
